package Lec2;

public class to_print_in_java {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

// There are 2 ways to print output in java 1) with println  , 2)without ln which is print
// Shortcut to write System.out.println is use write Syso then press ctrl+space
		
		System.out.println("hey"); //Println use to print the next upcoming output from next line.
                           // Eg: in output after hey the next upcoming output which is Bie is in next line.

System.out.print("Bie");   // Without ln after print the next upcoming output will in the same line of prev output
                           // Eg: After Bie the next upcoming output which is Aditi is in the same line 
System.out.println("Aditi");
System.out.print("Cb");
	}

}
